// // This module implements a 2-bit Johnson counter that cycles through the sequence 11, 10, 00, 01 on the positive edge of the clock and resets to 11 when rst is asserted.
module johnson_counter (
	input clk,
	input rst,
	output reg [1:0] count);

	always @(posedge clk) begin
		if (rst)
			count <= 2'b00;
		else
			count <= {count[0], ~count[1]};
	end

endmodule
